ame(updatedAtB)) {\r\n                                return 0;\r\n                            }\r\n                            return updatedAtA.isBefore(updatedAtB) ? 1 : -1;\r\n                        }\r\n\r\n                        return dateA.isBefore(dateB) ? 1 : -1;\r\n                    })\r\n                }\r\n                return [];\r\n            }\r\n        }\r\n    }\r\n</script>"],"sourceRoot":""}]);
